model PublicResponse {
  id             String @id @default(cuid())
  organizationId String

  publishedConclusionId String

  /// counter_evidence | counter_argument | clarification | agreement_extension
  kind           String
  body           String
  citationUrl    String  @default("")
  submitterEmail String  @default("")
  orcid          String  @default("")
  pseudonymous   Boolean @default(false)

  /// Did the responder consent to having their response published if
  /// the firm decides to reply publicly? Captured per-response on the
  /// submission form (Round 17 prompt 31). When false, the founder
  /// queue suppresses the "Promote to PublicReply" affordance and the
  /// public-article appendix never renders this row.
  publishConsent Boolean @default(false)

  /// pending | approved | rejected | engaged | archived
  status        String @default("pending")
  moderatorNote String @default("")

  createdAt DateTime  @default(now())
  seenAt    DateTime?

  organization Organization        @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  published    PublishedConclusion @relation(fields: [publishedConclusionId], references: [id], onDelete: Cascade)
  triage       ResponseTriage?
  publicReply  PublicReply?

  @@index([organizationId])
  @@index([publishedConclusionId])
  @@index([status])
  @@index([seenAt])
}

// ── Round 17 prompt 31: response triage + dialog loop ──────────────────────
//
// `ResponseTriage` is a 1:1 sidecar to `PublicResponse` written by the
// Python classifier in `noosphere/literature/response_triage.py`. The
// triage row is the queue's source of priority (substantive vs noise);
// the founder retains the override via `manualLabel` / `manualReason`.
//
// The plaintext submitter email is NEVER duplicated here; we only keep
// the SHA-256 hash so the queue can flag repeat-spam senders without
// expanding the PII surface.
model ResponseTriage {
  id               String @id @default(cuid())
  organizationId   String
  publicResponseId String @unique

  /// SUBSTANTIVE_OBJECTION | CLARIFICATION_REQUEST | GENERAL_ENGAGEMENT | SPAM_NOISE
  label      String
  /// Founder override of `label`. Empty string = honour the classifier label.
  manualLabel String @default("")

  /// "" | too_short | promotional_link | off_topic | abusive_language | repeat_sender | low_information
  spamReason String @default("")
  /// Founder override of `spamReason` (audit trail; e.g. when un-spamming).
  manualReason String @default("")

  confidence  Float
  /// One-sentence reduction of the implied objection. Empty unless
  /// label == SUBSTANTIVE_OBJECTION. Feeds the severity rubric.
  impliedObjection String @default("") @db.Text
  rationale        String @default("") @db.Text
  usedLlm          Boolean @default(false)

  /// SHA-256 of the lowercased submitter email; "" for pseudonymous.
  senderHash          String  @default("")
  elevatedSenderFlag  Boolean @default(false)

  /// Severity input snapshot from the cascade graph at triage time —
  /// stored so the queue can sort by potential severity without a
  /// fresh cascade traversal on every page render. JSON shape mirrors
  /// `SeverityInputs` in `noosphere/peer_review/severity.py`.
  severityInputsJson String @default("{}")
  /// Cached numeric severity in [0, 1] derived from the snapshot.
  severityValue      Float  @default(0)

  createdAt DateTime  @default(now())
  /// Set when the founder archives the row (spam path or
  /// substantive-but-handled). Archived rows drop out of the queue.
  archivedAt   DateTime?
  archiveNote  String    @default("")

  organization   Organization   @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicResponse PublicResponse @relation(fields: [publicResponseId], references: [id], onDelete: Cascade)

  @@index([organizationId])
  @@index([organizationId, label])
  @@index([organizationId, archivedAt, severityValue])
  @@index([senderHash])
}

// `PublicReply` is the founder's reply, attached to a single
// `PublicResponse`. The founder can mark it `private` (emailed back to
// the responder; never published) or `public` (rendered in the article
// appendix). Public replies require BOTH the responder's
// `publishConsent` AND the founder's confirmation here — symmetric
// double opt-in, so neither side can publish unilaterally.
model PublicReply {
  id               String @id @default(cuid())
  organizationId   String
  publicResponseId String @unique
  founderId        String

  /// private | public
  visibility    String @default("private")
  body          String @db.Text

  /// True only when the founder explicitly confirmed the publish step
  /// AND the underlying PublicResponse.publishConsent was true at the
  /// time of confirmation. Snapshotted here so a later consent-revoke
  /// does not change the audit record.
  publishConfirmed     Boolean   @default(false)
  publishConfirmedAt   DateTime?

  /// Whether this reply also opened a review-queue item for the
  /// implied objection. Track here so the queue UI can show "already
  /// promoted" without a join.
  promotedToReview     Boolean   @default(false)
  /// Whether the reply triggered a revision-engine (prompt 16) input.
  /// Stores the RevisionEvent.id when set.
  triggeredRevisionId  String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization   Organization   @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicResponse PublicResponse @relation(fields: [publicResponseId], references: [id], onDelete: Cascade)
  founder        Founder        @relation("PublicReplyFounder", fields: [founderId], references: [id])

  @@index([organizationId])
  @@index([organizationId, visibility, publishConfirmed])
}

model ContactSubmission {
  id             String    @id @default(cuid())
  createdAt      DateTime  @default(now())
  fromName       String
  fromEmail      String
  subject        String?
  body           String
  organizationId String?
  ipHash         String
  userAgent      String?
  triagedAt      DateTime?
  triagedBy      String?
  notes          String?

  @@index([createdAt])
  @@index([fromEmail])
  @@index([ipHash, createdAt])
  @@index([triagedAt, createdAt])
}

// ── ContradictionFinding + scores — mirrors pipeline outputs ────────────────

model Contradiction {
  id             String @id @default(cuid())
  organizationId String

  claimAId     String
  claimBId     String
  severity     Float
  sixLayerJson String?
  narrative    String   @default("")
  createdAt    DateTime @default(now())

  // ── Source tracking ───────────────────────────────────────────────
  // The upload whose ingestion run produced this contradiction row.

model Organization {
  id        String    @id @default(cuid())
  /// URL-safe tenant key (login, subdomains, worker routing)
  slug      String    @unique
  name      String
  /// Soft-delete grace window (hard-delete after policy window)
  deletedAt DateTime?
  createdAt DateTime  @default(now())
  updatedAt DateTime  @updatedAt

  founders                 Founder[]
  sessions                 Session[]
  uploads                  Upload[]
  conclusions              Conclusion[]
  contradictions           Contradiction[]
  driftEvents              DriftEvent[]
  researchSuggestions      ResearchSuggestion[]
  reviewItems              ReviewItem[]
  openQuestions            OpenQuestion[]
  auditEvents              AuditEvent[]
  publicationReviews       PublicationReview[]
  publishedConclusions     PublishedConclusion[]
  publicResponses          PublicResponse[]
  responseTriages          ResponseTriage[]
  publicReplies            PublicReply[]
  apiKeys                  ApiKey[]
  currentEvents            CurrentEvent[]
  eventOpinions            EventOpinion[]
  methodologyProfiles      MethodologyProfile[]
  methodologyQualityScores MethodologyQualityScore[]
  socialPosts              SocialPost[]
  operatorStates           OperatorState[]
  forecastMarkets          ForecastMarket[]
  forecastPredictions      ForecastPrediction[]
  forecastTraces           ForecastTrace[]
  forecastBets             ForecastBet[]
  forecastPortfolios       ForecastPortfolioState[]
  watchedMarkets           WatchedMarket[]
  conclusionMethods        ConclusionMethod[]
  methodTrackRecords       MethodTrackRecord[]
  methodVersions           MethodVersion[]
  anchorRevisions          AnchorRevision[]
  domainBoundVerdicts      DomainBoundVerdict[]
  calibrationModels        CalibrationModel[]
  recalibrationOverrides   RecalibrationOverride[]
  revisionEvents           RevisionEvent[]
  sourceStandings          SourceStanding[]
  sourceTriageItems        SourceTriageItem[]
  sourceCredibility        SourceCredibilityUpdate[]
  citationVerdicts         CitationVerdict[]
  attentionActions         AttentionAction[]
  subscribers              Subscriber[]
  principles               Principle[]
  addenda                  Addendum[]
}

// ── Founders (portal users) — maps to FounderProfile in noosphere/models.py ─

model Founder {
  id             String       @id @default(cuid())
  organizationId String
  organization   Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  name                    String
  username                String
  email                   String
  passwordHash            String
  // Role ladder — see src/lib/roles.ts for the predicate helpers and
  // the full description of each tier:
  //   admin   → full read + write + can change other founders' roles
  //   founder → full read + write
  //   viewer  → read-only; every write API returns 403 and every UI
  //              affordance for writes is hidden
  // Default "founder" preserves prior behaviour: anyone added via
  // scripts/add-founder.ts is read+write unless explicitly seeded
  // with ADD_FOUNDER_ROLE=viewer or =admin. Validation lives at the
  // application layer; the column stays TEXT so adding a future tier
  // is a docstring + helper change, not a migration.
  role                    String    @default("founder") // admin | founder | viewer
  bio                     String?
  displayName             String?
  roleTitle               String?
  publicUrl               String?
  avatar                  String?
  accountNudgeDismissedAt DateTime?

  /// Maps to FounderProfile.id in Noosphere
  noosphereId String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  sessions                   Session[]
  uploads                    Upload[]
  auditEvents                AuditEvent[]
  deletionRequests           DeletionRequest[]
  attributedConclusions      Conclusion[]                @relation("ConclusionFounder")
  researchSuggestions        ResearchSuggestion[]
  reviewResolutions          ReviewItem[]                @relation("ReviewResolver")
  publicationReviews         PublicationReview[]         @relation("PublicationReviewer")
  recalibrationOverrides     RecalibrationOverride[]
  apiKeys                    ApiKey[]
  conclusionDeletionRequests ConclusionDeletionRequest[]
  dashboardDismissals        DashboardDismissal[]
  resolvedContradictions     Contradiction[]             @relation("ContradictionResolver")
  revisionEvents             RevisionEvent[]
  publicReplies              PublicReply[]               @relation("PublicReplyFounder")
  attentionActions           AttentionAction[]

  /// Opt-in flag for the daily morning digest email summarising open
  /// high-severity attention items. Default `false` — silent until the
  /// founder explicitly opts in. See `src/lib/dailyDigestEmail.ts`.
  dailyDigestOptIn Boolean @default(false)

  @@unique([organizationId, email])
  @@unique([organizationId, username])
  @@index([organizationId])
}

/// Browser session (server-side row; cookie carries signed opaque token)
model Session {
  id             String   @id @default(cuid())
  organizationId String
  founderId      String
  token          String   @unique
  expiresAt      DateTime
  createdAt      DateTime @default(now())

  founder      Founder      @relation(fields: [founderId], references: [id], onDelete: Cascade)
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([founderId])
}

// ── Uploads ────────────────────────────────────────────────────────────────

model Upload {
  id             String @id @default(cuid())
  organizationId String
  founderId      String

  title            String
  description      String?
  sourceType       String   @default("written") // written | annotation | external | transcript
  originalName     String
  mimeType         String
  filePath         String
  fileSize         Int
  textContent      String?
  blurb            String?
  // Status ladder (see src/lib/uploadStatus.ts for the canonical
  // vocabulary + UI labels). `pending | processing | ingested | failed`
  // are load-bearing strings from the init migration; `extracting` and
  // `awaiting_ingest` were added alongside the Wave-1 audio/PDF
  // extractors so founders can see which stage of the pipeline a row is
  // in (Whisper/pypdf vs. claim extraction) instead of a single opaque
  // "processing".
  status           String   @default("pending") // pending | extracting | awaiting_ingest | processing | ingested | failed
  processLog       String   @default("") // streamed CLI stdout/stderr
  claimsCount      Int?
  methodCount      Int?
  substCount       Int?
  principleCount   Int?
  errorMessage     String?
  // How the text was obtained for this upload, set by the noosphere
  // extractor dispatcher on success. Free-form string — e.g.
  // "passthrough", "faster-whisper", "openai-whisper-1", "pypdf",
  // "ocrmypdf". Rendered in the dashboard detail row so the founder
  // knows whether a transcript/PDF extract was reliable.
  extractionMethod String?
  createdAt        DateTime @default(now())
  updatedAt        DateTime @updatedAt

  // ── Public blog fields ─────────────────────────────────────────────
  // An Upload becomes a public blog post when `publishedAt IS NOT NULL`.
  // Default is null → the upload remains a private founder artifact.
  // `slug` is the URL-safe identifier used for `/post/:slug`; it's
  // generated from `title` at publish time and guaranteed unique across
  // the whole table (not per-org — the blog is a single public surface).
  // `blogExcerpt` is the card/list summary shown on the index; if null
  // we derive one from the first ~280 chars of `textContent`.
  // `authorBio` lets the founder override the displayed byline (e.g.
  // for guest posts or co-authored work); otherwise we show
  // Founder.name.
  publishedAt DateTime?
  slug        String?   @unique
  blogExcerpt String?
  authorBio   String?

  // ── Soft delete ────────────────────────────────────────────────────
  // `deletedAt` is the single source of truth for "this upload has
  // been removed". Every query that surfaces uploads to the UI must
  // filter by `deletedAt IS NULL`; we keep the row around so the audit
  // trail (AuditEvent pointing at this upload) stays intact, and so a
  // DB-level restore is possible if a deletion turns out to be a
  // mistake. Only the uploader can set this directly; peers must go
  // through a DeletionRequest, which the owner accepts (setting
  // `deletedAt=now`) or declines.
  deletedAt DateTime?

model PublishedConclusion {
  id                 String @id @default(cuid())
  organizationId     String
  sourceConclusionId String

  slug    String
  version Int    @default(1)
  /// CONCLUSION for reviewed firm conclusions; ARTICLE for generated longform essays.
  kind    String @default("CONCLUSION")

  /// Headline discounted confidence (SP05); stated founder/model confidence alongside in JSON.
  discountedConfidence      Float
  statedConfidence          Float  @default(0)
  calibrationDiscountReason String @default("")

  /// Full page payload: evidence, exit conditions, adversarial, voice map, timeline, citations.
  payloadJson String @default("{}")

  /// Zenodo DOI for this revision (minted on first publish of revision).
  doi            String @default("")
  zenodoRecordId String @default("")

  publishedAt DateTime @default(now())

  organization Organization          @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  responses    PublicResponse[]
  signature    PublicationSignature?

  @@unique([slug, version])
  @@index([organizationId])
  @@index([slug])
  @@index([kind, publishedAt])
}

/// Cryptographic signature for a PublishedConclusion.
///
/// Generated by the noosphere CLI (`noosphere ledger sign-publication`) at
/// the publish moment. Private signing keys NEVER live in the web app; the
/// web app stores the signature artifact and serves it via
/// /api/public/signature/[slug]. Readers can re-verify with
/// `noosphere ledger verify-publication <slug>`.
model PublicationSignature {
  id                     String   @id @default(cuid())
  publishedConclusionId  String   @unique
  slug                   String
  version                Int

  /// Hex-encoded SHA-256 of the canonicalized inputs (see noosphere.ledger.canonicalize).
  canonicalHash  String
  /// Hex-encoded Ed25519 signature over the canonical hash bytes.
  signatureHex   String
  /// Short fingerprint (sha256[:16]) of the verify key used to sign.
  keyFingerprint String
  /// ISO-8601 UTC timestamp at the moment of signing.
  signedAt       String

  /// Full PublicationSignature artifact as JSON (canonicalInput + signature),
  /// served verbatim to the public verifier.
  payloadJson String @default("{}")

  createdAt DateTime @default(now())

  publishedConclusion PublishedConclusion @relation(fields: [publishedConclusionId], references: [id], onDelete: Cascade)

  @@index([slug, version])
  @@index([keyFingerprint])
}

// ── Self-critique addenda ──────────────────────────────────────────────────
//
// Quarterly self-critique (see `noosphere/peer_review/self_critique.py`)
// can recommend that a published article carry a dated addendum block —
// "On <date> the firm re-reviewed this article and found <summary>".
// The addendum is visibly later content; the original article body is
// never edited through this path. Only `publishedAt` is shown publicly;
// `pending` and `dismissed` rows are operator-only.
model Addendum {
  id             String @id @default(cuid())
  organizationId String

  /// Slug of the article the addendum attaches to. We key by slug (not
  /// publishedConclusionId) so a generated-article post and its
  /// matching `PublishedConclusion` row can share addenda without
  /// having to be linked through the same id.
  articleSlug String

  /// Optional pointer at the noosphere-side article id, kept for audit
  /// trails so the founder can correlate an addendum with the upstream
  /// run.
  noosphereArticleId String?

  /// The self-critique finding that produced this addendum (free-form
  /// — used only for cross-referencing).
  findingId String @default("")

  /// One-sentence summary shown in the public block ("the firm
  /// re-reviewed this article and found …").
  summary String @db.Text
  /// Full body of the addendum. Markdown is allowed; the public page
  /// renders it inside a dated block below the original article.
  body String @default("") @db.Text

  /// pending | published | dismissed. Only `published` rows surface on
  /// the public page; `dismissed` carries `dismissedReason`.
  status String @default("pending")

  /// Free-form label of the reviewer configuration that produced the
  /// finding (e.g. `self-critique:v1`). Recorded so the firm can prove
  /// the self-critique pass used a configuration distinct from the
  /// original publication's swarm.
  reviewerConfig String @default("")

  createdAt       DateTime  @default(now())
  publishedAt     DateTime?
  dismissedAt     DateTime?
  dismissedReason String    @default("") @db.Text

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId, articleSlug, status])

model RevisionEvent {
  id             String @id @default(cuid())
  organizationId String
  /// Plan id from the noosphere engine (sha256 over inputs+thresholds);
  /// duplicates indicate idempotent re-submits and are allowed.
  planId         String
  /// Founder who confirmed the revision in the preview modal.
  founderId      String

  /// JSON: [{ claim_id, weight, new_evidence }] — the RevisionInput batch.
  inputsJson            String
  /// JSON: full RevisionPlan.to_dict() — frozen at commit time.
  planJson              String
  /// JSON: { conclusion_id: confidence_before } — the before-snapshot.
  preConfidenceSnapshot String
  /// Conclusions whose confidence changed by > δ at commit time. Stored
  /// as a denormalised JSON array of conclusion ids so the UI can build
  /// the "updated" pill query without parsing planJson on every page
  /// render. Source of truth is still planJson.
  affectedConclusionIds String @default("[]")

  /// `true` when the founder typed the K-cap confirmation phrase. Always
  /// `false` for revisions whose affected_count <= K; informational only.
  typedConfirmation Boolean @default(false)

  createdAt  DateTime  @default(now())
  revertedAt DateTime?

  founder      Founder      @relation(fields: [founderId], references: [id])
  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([organizationId, createdAt])
  @@index([planId])
}

// ── API keys for machine-to-machine auth (Dialectic auto-sync, scripts, etc.) ─
//
// Store the *hash* of the key, never the plaintext. The plaintext is returned
// once at creation time. Revocation = set `revokedAt`. The key plaintext
// should look like `tcx_<founderId>_<64-hex-random>` so the client can send
// the founderId bits without a DB lookup for routing, and the random tail is
// the secret. `authenticateApiKey()` in src/lib/apiKeyAuth.ts implements
// the verification (bcrypt compare against `keyHash`).
model ApiKey {
  id             String @id @default(cuid())
  organizationId String
  /// Founder the key acts on behalf of — uploads are attributed to them.
  founderId      String

