1	/**
2	 * Response-triage helpers for the founder workspace.
3	 *
4	 * The authoritative classifier lives in
5	 * `noosphere/noosphere/literature/response_triage.py` (Python, with the
6	 * firm's LLM client). This module is the codex-side bridge:
7	 *
8	 *   - `seedTriageRow` runs a deliberately small JS heuristic at
9	 *     submission time so the queue always has a row to render. It
10	 *     mirrors the four-label schema from the Python classifier and
11	 *     records `usedLlm = false`. The Python pass refines the row
12	 *     later (offline / scheduled) and overwrites `label`,
13	 *     `impliedObjection`, etc.
14	 *
15	 *   - `listTriageQueue` powers the founder queue page. Substantive
16	 *     responses surface first, ordered by cached severity descending.
17	 *     Spam_noise is filtered unless `includeArchived` is set.
18	 *
19	 *   - `getTriageDetail` powers the per-response detail view. It joins
20	 *     the original PublicResponse, the triage row, any existing reply,
21	 *     and the conclusion title.
22	 *
23	 * The Python and JS code share the four-label / six-spam-reason
24	 * vocabulary by string. Don't drift them.
25	 */
26	
27	import { db } from "@/lib/db";
28	import { parsePublicationPayload } from "@/lib/conclusionsRead";
29	
30	export const TRIAGE_LABELS = [
31	  "SUBSTANTIVE_OBJECTION",
32	  "CLARIFICATION_REQUEST",
33	  "GENERAL_ENGAGEMENT",
34	  "SPAM_NOISE",
35	] as const;
36	export type TriageLabel = (typeof TRIAGE_LABELS)[number];
37	
38	export const SPAM_REASONS = [
39	  "",
40	  "too_short",
41	  "promotional_link",
42	  "off_topic",
43	  "abusive_language",
44	  "repeat_sender",
45	  "low_information",
46	] as const;
47	export type SpamReason = (typeof SPAM_REASONS)[number];
48	
49	export const REPLY_VISIBILITIES = ["private", "public"] as const;
50	export type ReplyVisibility = (typeof REPLY_VISIBILITIES)[number];
51	
52	const MIN_BODY_CHARS = 20;
53	
54	const PROMO_TOKENS = [
55	  "click here",
56	  "buy now",
57	  "free trial",
58	  "make money",
59	  "subscribe to",
60	  "limited time",
61	  "viagra",
62	  "casino",
63	  "crypto giveaway",
64	];
65	
66	const ABUSE_TOKENS = ["idiot", "moron", "shut up", "garbage"];
67	
68	const OBJECTION_TOKENS = [
69	  "however",
70	  "but ",
71	  "disagree",
72	  "incorrect",
73	  "wrong",
74	  "evidence shows",
75	  "data show",
76	  "contradict",
77	  "actually",
78	  "fails to",
79	  "overlook",
80	  "ignores",
81	  "the study",
82	];
83	
84	const CLARIFICATION_TOKENS = [
85	  "could you clarify",
86	  "what do you mean",
87	  "can you explain",
88	];
89	
90	export type SeedTriageInput = {
91	  responseId: string;
92	  organizationId: string;
93	  kind: string;
94	  body: string;
95	  citationUrl: string;
96	  submitterEmail: string;
97	};
98	
99	export type SeedTriageOutput = {
100	  label: TriageLabel;
101	  spamReason: SpamReason;
102	  confidence: number;
103	  rationale: string;
104	  senderHash: string;
105	  elevatedSenderFlag: boolean;
106	};
107	
108	/**
109	 * Compute and persist a `ResponseTriage` row for a freshly submitted
110	 * PublicResponse. Idempotent — calling twice on the same response does
111	 * not duplicate (we use upsert against the unique `publicResponseId`).
112	 *
113	 * The heuristic is intentionally minimal. The Python pass is the
114	 * authority; this exists so the queue is never empty between
115	 * submission and the next classifier run.
116	 */
117	export async function seedTriageRow(input: SeedTriageInput): Promise<SeedTriageOutput> {
118	  const verdict = jsHeuristic(input);
119	  const senderHash = input.submitterEmail
120	    ? await sha256Hex(input.submitterEmail.trim().toLowerCase())
121	    : "";
122	
123	  const elevated = senderHash ? await senderSpamCount(senderHash, input.organizationId) >= 2 : false;
124	  let spamReason = verdict.spamReason;
125	  if (verdict.label === "SPAM_NOISE" && elevated && (spamReason === "" || spamReason === "low_information")) {
126	    spamReason = "repeat_sender";
127	  }
128	  if (verdict.label !== "SPAM_NOISE") spamReason = "";
129	
130	  await db.responseTriage.upsert({
131	    where: { publicResponseId: input.responseId },
132	    create: {
133	      organizationId: input.organizationId,
134	      publicResponseId: input.responseId,
135	      label: verdict.label,
136	      spamReason,
137	      confidence: verdict.confidence,
138	      rationale: verdict.rationale,
139	      usedLlm: false,
140	      senderHash,
141	      elevatedSenderFlag: elevated,
142	      severityValue: verdict.label === "SUBSTANTIVE_OBJECTION" ? 0.5 : 0,
143	    },
144	    update: {
145	      label: verdict.label,
146	      spamReason,
147	      confidence: verdict.confidence,
148	      rationale: verdict.rationale,
149	      senderHash,
150	      elevatedSenderFlag: elevated,
151	    },
152	  });
153	
154	  return {
155	    label: verdict.label,
156	    spamReason,
157	    confidence: verdict.confidence,
158	    rationale: verdict.rationale,
159	    senderHash,
160	    elevatedSenderFlag: elevated,
161	  };
162	}
163	
164	function jsHeuristic(input: SeedTriageInput): {
165	  label: TriageLabel;
166	  spamReason: SpamReason;
167	  confidence: number;
168	  rationale: string;
169	} {
170	  const body = (input.body || "").replace(/\s+/g, " ").trim();
171	  const lower = body.toLowerCase();
172	  const charN = body.length;
173	
174	  if (charN < MIN_BODY_CHARS) {
175	    return {
176	      label: "SPAM_NOISE",
177	      spamReason: "too_short",
178	      confidence: 0.95,
179	      rationale: `body length ${charN} < ${MIN_BODY_CHARS}`,
180	    };
181	  }
182	  for (const t of PROMO_TOKENS) {
183	    if (lower.includes(t)) {
184	      return { label: "SPAM_NOISE", spamReason: "promotional_link", confidence: 0.9, rationale: `promo: ${t}` };
185	    }
186	  }
187	  for (const t of ABUSE_TOKENS) {
188	    if (lower.includes(t)) {
189	      return { label: "SPAM_NOISE", spamReason: "abusive_language", confidence: 0.75, rationale: `abuse: ${t}` };
190	    }
191	  }
192	
193	  const kindPriors: Record<string, TriageLabel> = {
194	    counter_evidence: "SUBSTANTIVE_OBJECTION",
195	    counter_argument: "SUBSTANTIVE_OBJECTION",
196	    clarification: "CLARIFICATION_REQUEST",
197	    agreement_extension: "GENERAL_ENGAGEMENT",
198	  };
199	  const prior: TriageLabel = kindPriors[input.kind] ?? "GENERAL_ENGAGEMENT";
200	
201	  const hasQuestion = body.includes("?");
202	  const objHit = OBJECTION_TOKENS.some((t) => lower.includes(t));
203	  const clarHit = CLARIFICATION_TOKENS.some((t) => lower.includes(t));
204	  const hasCitation = input.citationUrl.trim().length > 0;
205	  const longBody = charN >= 200;
206	
207	  const score: Record<TriageLabel, number> = {
208	    SUBSTANTIVE_OBJECTION: 0,
209	    CLARIFICATION_REQUEST: 0,
210	    GENERAL_ENGAGEMENT: 0,
211	    SPAM_NOISE: 0,
212	  };
213	  score[prior] += 0.35;
214	  if (objHit) score.SUBSTANTIVE_OBJECTION += 0.3;
215	  if (hasCitation) score.SUBSTANTIVE_OBJECTION += 0.2;
216	  if (longBody) score.SUBSTANTIVE_OBJECTION += 0.15;
217	  if (hasQuestion) score.CLARIFICATION_REQUEST += 0.3;
218	  if (clarHit) score.CLARIFICATION_REQUEST += 0.25;
219	  if (!objHit && !hasQuestion && !clarHit) score.GENERAL_ENGAGEMENT += 0.2;
220	
221	  let label: TriageLabel = "GENERAL_ENGAGEMENT";
222	  let best = -1;
223	  for (const k of TRIAGE_LABELS) {
224	    if (score[k] > best) {
225	      best = score[k];
226	      label = k;
227	    }
228	  }
229	
230	  if (label === "GENERAL_ENGAGEMENT" && charN < MIN_BODY_CHARS * 2 && !hasCitation) {
231	    return {
232	      label: "SPAM_NOISE",
233	      spamReason: "low_information",
234	      confidence: 0.6,
235	      rationale: "short engagement-only body, no question, no citation",
236	    };
237	  }
238	
239	  return {
240	    label,
241	    spamReason: "",
242	    confidence: Math.max(0, Math.min(1, best)),
243	    rationale: `chars=${charN}; prior=${prior}; q=${hasQuestion}; obj=${objHit}; cite=${hasCitation}`,
244	  };
245	}
246	
247	async function sha256Hex(input: string): Promise<string> {
248	  const data = new TextEncoder().encode(input);
249	  const buf = await crypto.subtle.digest("SHA-256", data);
250	  return Array.from(new Uint8Array(buf))
251	    .map((b) => b.toString(16).padStart(2, "0"))
252	    .join("");
253	}
254	
255	async function senderSpamCount(senderHash: string, organizationId: string): Promise<number> {
256	  return db.responseTriage.count({
257	    where: {
258	      organizationId,
259	      senderHash,
260	      label: "SPAM_NOISE",
261	    },
262	  });
263	}
264	
265	// ── queue + detail readers ───────────────────────────────────────────
266	
267	export type TriageQueueRow = {
268	  id: string;
269	  responseId: string;
270	  label: TriageLabel;
271	  effectiveLabel: TriageLabel;
272	  spamReason: SpamReason;
273	  confidence: number;
274	  severityValue: number;
275	  impliedObjection: string;
276	  rationale: string;
277	  archivedAt: Date | null;
278	  archiveNote: string;
279	  elevatedSenderFlag: boolean;
280	  createdAt: Date;
281	  publicResponse: {
282	    id: string;
283	    kind: string;
284	    body: string;
285	    citationUrl: string;
286	    submitterEmail: string;
287	    pseudonymous: boolean;
288	    publishConsent: boolean;
289	    createdAt: Date;
290	    seenAt: Date | null;
291	  };
292	  conclusion: {
293	    id: string;
294	    slug: string;
295	    version: number;
296	    title: string;
297	  };
298	  reply: {
299	    id: string;
300	    visibility: ReplyVisibility;
301	    publishConfirmed: boolean;
302	    promotedToReview: boolean;
303	    triggeredRevisionId: string | null;
304	  } | null;
305	};
306	
307	export type TriageQueueFilter = {
308	  organizationId: string;
309	  /** When false (default) excludes SPAM_NOISE and archived rows. */
310	  includeNoise?: boolean;
311	  includeArchived?: boolean;
312	  limit?: number;
313	};
314	
315	type RawTriageRow = Awaited<ReturnType<typeof loadRawRows>>[number];
316	
317	async function loadRawRows(filter: TriageQueueFilter) {
318	  return db.responseTriage.findMany({
319	    where: {
320	      organizationId: filter.organizationId,
321	      ...(filter.includeArchived ? {} : { archivedAt: null }),
322	    },
323	    orderBy: [
324	      { severityValue: "desc" },
325	      { createdAt: "desc" },
326	    ],
327	    take: filter.limit ?? 200,
328	    include: {
329	      publicResponse: {
330	        include: {
331	          published: {
332	            select: { id: true, slug: true, version: true, payloadJson: true },
333	          },
334	          publicReply: {
335	            select: {
336	              id: true,
337	              visibility: true,
338	              publishConfirmed: true,
339	              promotedToReview: true,
340	              triggeredRevisionId: true,
341	            },
342	          },
343	        },
344	      },
345	    },
346	  });
347	}
348	
349	export async function listTriageQueue(filter: TriageQueueFilter): Promise<TriageQueueRow[]> {
350	  const rows = await loadRawRows(filter);
351	  const includeNoise = filter.includeNoise ?? false;
352	  return rows
353	    .map(toQueueRow)
354	    .filter((row) => includeNoise || row.effectiveLabel !== "SPAM_NOISE");
355	}
356	
357	export async function getTriageDetail(
358	  organizationId: string,
359	  triageId: string,
360	): Promise<TriageQueueRow | null> {
361	  const row = await db.responseTriage.findFirst({
362	    where: { id: triageId, organizationId },
363	    include: {
364	      publicResponse: {
365	        include: {
366	          published: {
367	            select: { id: true, slug: true, version: true, payloadJson: true },
368	          },
369	          publicReply: {
370	            select: {
371	              id: true,
372	              visibility: true,
373	              publishConfirmed: true,
374	              promotedToReview: true,
375	              triggeredRevisionId: true,
376	            },
377	          },
378	        },
379	      },
380	    },
381	  });
382	  if (!row) return null;
383	  return toQueueRow(row);
384	}
385	
386	export async function getReplyBody(
387	  organizationId: string,
388	  triageId: string,
389	): Promise<string | null> {
390	  const row = await db.responseTriage.findFirst({
391	    where: { id: triageId, organizationId },
392	    select: {
393	      publicResponse: {
394	        select: { publicReply: { select: { body: true } } },
395	      },
396	    },
397	  });
398	  return row?.publicResponse?.publicReply?.body ?? null;
399	}
400	
401	function toQueueRow(row: RawTriageRow): TriageQueueRow {
402	  const label = (row.label as TriageLabel) ?? "GENERAL_ENGAGEMENT";
403	  const effectiveLabel = ((row.manualLabel as TriageLabel) || label) as TriageLabel;
404	  const spamReason = (row.manualReason || row.spamReason || "") as SpamReason;
405	  const conclusion = parsePublicationPayload({
406	    payloadJson: row.publicResponse.published.payloadJson,
407	    slug: row.publicResponse.published.slug,
408	  });
409	  return {
410	    id: row.id,
411	    responseId: row.publicResponseId,
412	    label,
413	    effectiveLabel,
414	    spamReason,
415	    confidence: row.confidence,
416	    severityValue: row.severityValue,
417	    impliedObjection: row.impliedObjection,
418	    rationale: row.rationale,
419	    archivedAt: row.archivedAt,
420	    archiveNote: row.archiveNote,
421	    elevatedSenderFlag: row.elevatedSenderFlag,
422	    createdAt: row.createdAt,
423	    publicResponse: {
424	      id: row.publicResponse.id,
425	      kind: row.publicResponse.kind,
426	      body: row.publicResponse.body,
427	      citationUrl: row.publicResponse.citationUrl,
428	      submitterEmail: row.publicResponse.submitterEmail,
429	      pseudonymous: row.publicResponse.pseudonymous,
430	      publishConsent: row.publicResponse.publishConsent,
431	      createdAt: row.publicResponse.createdAt,
432	      seenAt: row.publicResponse.seenAt,
433	    },
434	    conclusion: {
435	      id: row.publicResponse.published.id,
436	      slug: row.publicResponse.published.slug,
437	      version: row.publicResponse.published.version,
438	      title: conclusion.conclusionText,
439	    },
440	    reply: row.publicResponse.publicReply
441	      ? {
442	          id: row.publicResponse.publicReply.id,
443	          visibility: row.publicResponse.publicReply.visibility as ReplyVisibility,
444	          publishConfirmed: row.publicResponse.publicReply.publishConfirmed,
445	          promotedToReview: row.publicResponse.publicReply.promotedToReview,
446	          triggeredRevisionId: row.publicResponse.publicReply.triggeredRevisionId,
447	        }
448	      : null,
449	  };
450	}
451	
452	// ── public-article surface ───────────────────────────────────────────
453	
454	export type ReaderResponseEntry = {
455	  responseId: string;
456	  responderLabel: string;
457	  responseBody: string;
458	  responseCitationUrl: string;
459	  replyBody: string;
460	  repliedAt: Date;
461	};
462	
463	/**
464	 * The "Reader responses" appendix payload for a single published
465	 * conclusion. Returns only entries where:
466	 *   - the responder consented to publication
467	 *   - the founder confirmed `visibility=public` AND `publishConfirmed=true`
468	 *   - the underlying response is not in `rejected` / `archived` state
469	 */
470	export async function listPublicReaderResponses(
471	  organizationId: string,
472	  publishedConclusionId: string,
473	): Promise<ReaderResponseEntry[]> {
474	  const rows = await db.publicReply.findMany({
475	    where: {
476	      organizationId,
477	      visibility: "public",
478	      publishConfirmed: true,
479	      publicResponse: {
480	        publishedConclusionId,
481	        publishConsent: true,
482	        status: { notIn: ["rejected", "archived"] },
483	      },
484	    },
485	    orderBy: { publishConfirmedAt: "desc" },
486	    include: {
487	      publicResponse: {
488	        select: {
489	          id: true,
490	          body: true,
491	          citationUrl: true,
492	          submitterEmail: true,
493	          orcid: true,
494	          pseudonymous: true,
495	        },
496	      },
497	    },
498	  });
499	
500	  return rows.map((row) => ({
501	    responseId: row.publicResponse.id,
502	    responderLabel: respondentDisplay(row.publicResponse),
503	    responseBody: row.publicResponse.body,
504	    responseCitationUrl: row.publicResponse.citationUrl,
505	    replyBody: row.body,
506	    repliedAt: row.publishConfirmedAt ?? row.updatedAt,
507	  }));
508	}
509	
510	function respondentDisplay(resp: {
511	  pseudonymous: boolean;
512	  submitterEmail: string;
513	  orcid: string;
514	}): string {
515	  if (resp.pseudonymous) return resp.orcid ? `Reader (ORCID ${resp.orcid})` : "Reader";
516	  // We never expose the raw email — the public surface gets the
517	  // localpart only, so a poster's domain doesn't leak.
518	  const at = resp.submitterEmail.indexOf("@");
519	  if (at <= 0) return "Reader";
520	  return resp.submitterEmail.slice(0, at);
521	}
522

