1	"use server";
2	
3	/**
4	 * Server actions for the response-triage workspace.
5	 *
6	 * Each action checks tenancy, mutates one row, and revalidates the
7	 * affected paths. The actions deliberately do not branch on label —
8	 * the founder is the gatekeeper, not the classifier. We do enforce
9	 * the consent-symmetry rule (a public reply requires both
10	 * `PublicResponse.publishConsent` AND `publishConfirmed=true` here)
11	 * because that protects the responder from a unilateral publish.
12	 */
13	
14	import { revalidatePath } from "next/cache";
15	
16	import { db } from "@/lib/db";
17	import { sendMail } from "@/lib/mail";
18	import { conclusionPublicUrl, conclusionTitle, notifyFromAddress } from "@/lib/responsesEmail";
19	import { TRIAGE_LABELS, type TriageLabel } from "@/lib/responseTriageApi";
20	import { requireTenantContext } from "@/lib/tenant";
21	
22	const QUEUE_PATH = "/responses/queue";
23	
24	function field(form: FormData, name: string): string {
25	  const v = form.get(name);
26	  return typeof v === "string" ? v : "";
27	}
28	
29	function escapeHtml(value: string): string {
30	  return value
31	    .replace(/&/g, "&amp;")
32	    .replace(/</g, "&lt;")
33	    .replace(/>/g, "&gt;")
34	    .replace(/"/g, "&quot;")
35	    .replace(/'/g, "&#39;");
36	}
37	
38	async function loadTriage(triageId: string, organizationId: string) {
39	  const row = await db.responseTriage.findFirst({
40	    where: { id: triageId, organizationId },
41	    include: {
42	      publicResponse: {
43	        include: {
44	          published: { select: { slug: true, version: true, payloadJson: true } },
45	        },
46	      },
47	    },
48	  });
49	  if (!row) throw new Error(`Triage row ${triageId} not found.`);
50	  return row;
51	}
52	
53	export async function archiveTriageAction(formData: FormData) {
54	  const tenant = await requireTenantContext();
55	  if (!tenant) throw new Error("Not authenticated.");
56	
57	  const triageId = field(formData, "triageId");
58	  if (!triageId) throw new Error("triageId is required.");
59	  const note = field(formData, "archiveNote").trim();
60	
61	  await db.responseTriage.updateMany({
62	    where: { id: triageId, organizationId: tenant.organizationId },
63	    data: { archivedAt: new Date(), archiveNote: note },
64	  });
65	
66	  revalidatePath(QUEUE_PATH);
67	  revalidatePath(`/responses/${triageId}`);
68	}
69	
70	export async function restoreTriageAction(formData: FormData) {
71	  const tenant = await requireTenantContext();
72	  if (!tenant) throw new Error("Not authenticated.");
73	
74	  const triageId = field(formData, "triageId");
75	  if (!triageId) throw new Error("triageId is required.");
76	
77	  await db.responseTriage.updateMany({
78	    where: { id: triageId, organizationId: tenant.organizationId },
79	    data: { archivedAt: null, archiveNote: "" },
80	  });
81	
82	  revalidatePath(QUEUE_PATH);
83	  revalidatePath(`/responses/${triageId}`);
84	}
85	
86	export async function overrideTriageLabelAction(formData: FormData) {
87	  const tenant = await requireTenantContext();
88	  if (!tenant) throw new Error("Not authenticated.");
89	
90	  const triageId = field(formData, "triageId");
91	  const manualLabel = field(formData, "manualLabel");
92	  const manualReason = field(formData, "manualReason");
93	  if (!triageId) throw new Error("triageId is required.");
94	  if (manualLabel && !TRIAGE_LABELS.includes(manualLabel as TriageLabel)) {
95	    throw new Error(`Unknown triage label: ${manualLabel}`);
96	  }
97	
98	  await db.responseTriage.updateMany({
99	    where: { id: triageId, organizationId: tenant.organizationId },
100	    data: {
101	      manualLabel,
102	      manualReason: manualReason.trim(),
103	    },
104	  });
105	
106	  revalidatePath(QUEUE_PATH);
107	  revalidatePath(`/responses/${triageId}`);
108	}
109	
110	export async function replyPrivateAction(formData: FormData) {
111	  const tenant = await requireTenantContext();
112	  if (!tenant) throw new Error("Not authenticated.");
113	
114	  const triageId = field(formData, "triageId");
115	  const body = field(formData, "body").trim();
116	  if (!triageId || !body) throw new Error("triageId and reply body are required.");
117	
118	  const row = await loadTriage(triageId, tenant.organizationId);
119	  if (row.publicResponse.pseudonymous || !row.publicResponse.submitterEmail) {
120	    throw new Error("Cannot reply privately to a pseudonymous responder.");
121	  }
122	
123	  await db.publicReply.upsert({
124	    where: { publicResponseId: row.publicResponseId },
125	    create: {
126	      organizationId: tenant.organizationId,
127	      publicResponseId: row.publicResponseId,
128	      founderId: tenant.founderId,
129	      visibility: "private",
130	      body,
131	      publishConfirmed: false,
132	    },
133	    update: {
134	      body,
135	      visibility: "private",
136	      publishConfirmed: false,
137	      publishConfirmedAt: null,
138	      founderId: tenant.founderId,
139	    },
140	  });
141	
142	  const title = conclusionTitle({
143	    id: row.publicResponse.publishedConclusionId,
144	    slug: row.publicResponse.published.slug,
145	    payloadJson: row.publicResponse.published.payloadJson,
146	  });
147	  const url = conclusionPublicUrl({
148	    id: row.publicResponse.publishedConclusionId,
149	    slug: row.publicResponse.published.slug,
150	    version: row.publicResponse.published.version,
151	  });
152	  const replyText = `${body}\n\n— Theseus Codex (${url})\n`;
153	  await sendMail({
154	    to: row.publicResponse.submitterEmail,
155	    from: notifyFromAddress(),
156	    subject: `Re: your Theseus response on "${title.slice(0, 80)}"`,
157	    text: replyText,
158	    html: `<p style="white-space:pre-wrap">${escapeHtml(body)}</p><p>— Theseus Codex (<a href="${escapeHtml(url)}">${escapeHtml(url)}</a>)</p>`,
159	    headers: { "X-Theseus-Reply-Type": "private" },
160	  });
161	
162	  await db.publicResponse.updateMany({
163	    where: { id: row.publicResponseId, organizationId: tenant.organizationId },
164	    data: { status: "engaged" },
165	  });
166	
