3	import { useState } from "react";
4	
5	import type { PublishedConclusion } from "@/lib/conclusionsRead";
6	
7	const KINDS = [
8	  { id: "counter_evidence", label: "Counter-evidence" },
9	  { id: "counter_argument", label: "Counter-argument" },
10	  { id: "clarification", label: "Clarification request" },
11	  { id: "agreement_extension", label: "Agreement with extension" },
12	] as const;
13	
14	export default function RespondForm({ conclusions }: { conclusions: PublishedConclusion[] }) {
15	  const [publishedId, setPublishedId] = useState(conclusions[0]?.id ?? "");
16	  const [kind, setKind] = useState<string>(KINDS[0].id);
17	  const [body, setBody] = useState("");
18	  const [email, setEmail] = useState("");
19	  const [orcid, setOrcid] = useState("");
20	  const [citationUrl, setCitationUrl] = useState("");
21	  const [pseudonymous, setPseudonymous] = useState(false);
22	  const [publishConsent, setPublishConsent] = useState(false);
23	  const [msg, setMsg] = useState<string | null>(null);
24	  const [busy, setBusy] = useState(false);
25	  const scopedConclusion = conclusions.length === 1 ? conclusions[0] : null;
26	
27	  async function submit() {
28	    setMsg(null);
29	    if (!publishedId) {
30	      setMsg("No published conclusion is available for response.");
31	      return;
32	    }
33	    setBusy(true);
34	    try {
35	      const res = await fetch("/api/public/responses", {
36	        method: "POST",
37	        headers: { "Content-Type": "application/json" },
38	        body: JSON.stringify({
39	          publishedConclusionId: publishedId,
40	          kind,
41	          body,
42	          citationUrl,
43	          submitterEmail: email,
44	          orcid,
45	          pseudonymous,
46	          publishConsent,
47	        }),
48	      });
49	      const json = (await res.json().catch(() => ({}))) as { error?: string; ok?: boolean };
50	      if (!res.ok) {
51	        setMsg(json.error || `Submit failed (${res.status})`);
52	        return;
53	      }
54	      setMsg("Submitted. It will be reviewed before it can appear publicly.");
55	      setBody("");
56	      setCitationUrl("");
57	    } finally {
58	      setBusy(false);
59	    }
60	  }
61	
62	  return (
63	    <div className="public-card public-form-card">
64	      <p className="public-muted">Responses are reviewed before publication. Engaged responses trigger internal review.</p>
65	
66	      {scopedConclusion ? (
67	        <p className="public-muted mono" style={{ fontSize: "0.66rem", letterSpacing: "0.08em" }}>
68	          Responding to: &apos;{scopedConclusion.payload.conclusionText || scopedConclusion.slug}&apos;
69	        </p>
70	      ) : (
