/// Structured reader responses — moderation queue (SP10).
model PublicResponse {
  id             String @id @default(cuid())
  organizationId String

  publishedConclusionId String

  /// counter_evidence | counter_argument | clarification | agreement_extension
  kind           String
  body           String
  citationUrl    String  @default("")
  submitterEmail String  @default("")
  orcid          String  @default("")
  pseudonymous   Boolean @default(false)

  /// Did the responder consent to having their response published if
  /// the firm decides to reply publicly? Captured per-response on the
  /// submission form (Round 17 prompt 31). When false, the founder
  /// queue suppresses the "Promote to PublicReply" affordance and the
  /// public-article appendix never renders this row.
  publishConsent Boolean @default(false)

  /// pending | approved | rejected | engaged | archived
  status        String @default("pending")
  moderatorNote String @default("")

  createdAt DateTime  @default(now())
  seenAt    DateTime?

  organization Organization        @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  published    PublishedConclusion @relation(fields: [publishedConclusionId], references: [id], onDelete: Cascade)
  triage       ResponseTriage?
  publicReply  PublicReply?

  @@index([organizationId])
  @@index([publishedConclusionId])
  @@index([status])
  @@index([seenAt])
}

// ── Round 17 prompt 31: response triage + dialog loop ──────────────────────
//
// `ResponseTriage` is a 1:1 sidecar to `PublicResponse` written by the
// Python classifier in `noosphere/literature/response_triage.py`. The
// triage row is the queue's source of priority (substantive vs noise);
// the founder retains the override via `manualLabel` / `manualReason`.
//
// The plaintext submitter email is NEVER duplicated here; we only keep
// the SHA-256 hash so the queue can flag repeat-spam senders without
// expanding the PII surface.
model ResponseTriage {
  id               String @id @default(cuid())
  organizationId   String
  publicResponseId String @unique

  /// SUBSTANTIVE_OBJECTION | CLARIFICATION_REQUEST | GENERAL_ENGAGEMENT | SPAM_NOISE
  label      String
  /// Founder override of `label`. Empty string = honour the classifier label.
  manualLabel String @default("")

  /// "" | too_short | promotional_link | off_topic | abusive_language | repeat_sender | low_information
  spamReason String @default("")
  /// Founder override of `spamReason` (audit trail; e.g. when un-spamming).
  manualReason String @default("")

  confidence  Float
  /// One-sentence reduction of the implied objection. Empty unless
  /// label == SUBSTANTIVE_OBJECTION. Feeds the severity rubric.
  impliedObjection String @default("") @db.Text
  rationale        String @default("") @db.Text
  usedLlm          Boolean @default(false)

  /// SHA-256 of the lowercased submitter email; "" for pseudonymous.
  senderHash          String  @default("")
  elevatedSenderFlag  Boolean @default(false)

  /// Severity input snapshot from the cascade graph at triage time —
  /// stored so the queue can sort by potential severity without a
  /// fresh cascade traversal on every page render. JSON shape mirrors
  /// `SeverityInputs` in `noosphere/peer_review/severity.py`.
  severityInputsJson String @default("{}")
  /// Cached numeric severity in [0, 1] derived from the snapshot.
  severityValue      Float  @default(0)

  createdAt DateTime  @default(now())
  /// Set when the founder archives the row (spam path or
  /// substantive-but-handled). Archived rows drop out of the queue.
  archivedAt   DateTime?
  archiveNote  String    @default("")

  organization   Organization   @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicResponse PublicResponse @relation(fields: [publicResponseId], references: [id], onDelete: Cascade)

  @@index([organizationId])
  @@index([organizationId, label])
  @@index([organizationId, archivedAt, severityValue])
  @@index([senderHash])
}

// `PublicReply` is the founder's reply, attached to a single
// `PublicResponse`. The founder can mark it `private` (emailed back to
// the responder; never published) or `public` (rendered in the article
// appendix). Public replies require BOTH the responder's
// `publishConsent` AND the founder's confirmation here — symmetric
// double opt-in, so neither side can publish unilaterally.
model PublicReply {
  id               String @id @default(cuid())
  organizationId   String
  publicResponseId String @unique
  founderId        String

  /// private | public
  visibility    String @default("private")
  body          String @db.Text

  /// True only when the founder explicitly confirmed the publish step
  /// AND the underlying PublicResponse.publishConsent was true at the
  /// time of confirmation. Snapshotted here so a later consent-revoke
  /// does not change the audit record.
  publishConfirmed     Boolean   @default(false)
  publishConfirmedAt   DateTime?

  /// Whether this reply also opened a review-queue item for the
  /// implied objection. Track here so the queue UI can show "already
  /// promoted" without a join.
  promotedToReview     Boolean   @default(false)
  /// Whether the reply triggered a revision-engine (prompt 16) input.
  /// Stores the RevisionEvent.id when set.
  triggeredRevisionId  String?

  createdAt DateTime @default(now())
  updatedAt DateTime @updatedAt

  organization   Organization   @relation(fields: [organizationId], references: [id], onDelete: Restrict)
  publicResponse PublicResponse @relation(fields: [publicResponseId], references: [id], onDelete: Cascade)
  founder        Founder        @relation("PublicReplyFounder", fields: [founderId], references: [id])

  @@index([organizationId])
  @@index([organizationId, visibility, publishConfirmed])
}

model ContactSubmission {
  id             String    @id @default(cuid())
  createdAt      DateTime  @default(now())
  fromName       String
  fromEmail      String
  subject        String?
  body           String
  organizationId String?
  ipHash         String
  userAgent      String?
  triagedAt      DateTime?
  triagedBy      String?
  notes          String?

  @@index([createdAt])
  @@index([fromEmail])
  @@index([ipHash, createdAt])
  @@index([triagedAt, createdAt])
}

// ── ContradictionFinding + scores — mirrors pipeline outputs ────────────────

model Contradiction {
  id             String @id @default(cuid())
  organizationId String

  claimAId     String
  claimBId     String
  severity     Float
  sixLayerJson String?
  narrative    String   @default("")
  createdAt    DateTime @default(now())

  // ── Source tracking ───────────────────────────────────────────────
  // The upload whose ingestion run produced this contradiction row.
  // Nullable so the column can be backfilled from `noosphereId` patterns
  // on existing rows; the ingest pipeline sets it on every new row.
  // When the source upload is deleted the contradiction is hard-deleted
  // in the same transaction (see src/app/api/upload/[id]/delete/route.ts);
  // cross-upload contradictions (where claimA and claimB come from
  // different uploads) additionally die if EITHER of their referenced
  // Conclusions has already been orphan-deleted.
  sourceUploadId String?
  sourceUpload   Upload? @relation("ContradictionSourceUpload", fields: [sourceUploadId], references: [id])

  // ── Resolution tracking ────────────────────────────────────────────
  // A contradiction starts "active". A founder can resolve it
  // (acknowledged + addressed with a note) or dismiss it (false
  // positive). Non-active rows are hidden from the main view by
  // default but preserved for audit.
  status       String    @default("active") // active | resolved | dismissed
  resolution   String?
  resolvedById String?
  resolvedAt   DateTime?
  resolvedBy   Founder?  @relation("ContradictionResolver", fields: [resolvedById], references: [id])

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([sourceUploadId])
  @@index([status])
}

// ── ConclusionDeletionRequest ─────────────────────────────────────────
// Peer-to-peer "please delete this conclusion" workflow, mirroring
// DeletionRequest for uploads. A founder opens a request; the
// conclusion's attributed founder (or an admin) accepts or declines.
// On accept: hard-delete the Conclusion (and its ConclusionSource rows
// via FK cascade) so it's purged from the model.

model ConclusionDeletionRequest {
  id           String    @id @default(cuid())
  conclusionId String
  requesterId  String
  status       String    @default("pending") // pending | accepted | declined | cancelled
  reason       String?
  decision     String?
  createdAt    DateTime  @default(now())
  respondedAt  DateTime?

  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)
  requester  Founder    @relation(fields: [requesterId], references: [id])

  @@index([conclusionId])
  @@index([requesterId])
  @@index([status])
}

// ── DashboardDismissal ─────────────────────────────────────────────────
// Per-founder UI preference. Dismissing a conclusion from the dashboard
// hides it from *this* founder's homepage only — other founders in the
// same org still see it. Not a deletion.

model DashboardDismissal {
  id           String   @id @default(cuid())
  founderId    String
  conclusionId String
  createdAt    DateTime @default(now())

  founder    Founder    @relation(fields: [founderId], references: [id])
  conclusion Conclusion @relation(fields: [conclusionId], references: [id], onDelete: Cascade)

  @@unique([founderId, conclusionId])
  @@index([founderId])
  @@index([conclusionId])
}

// ── DriftEvent — mirrors noosphere.models.DriftEvent ───────────────────────
//
// Two distinct kinds of drift event share this table:
//
// 1. `targetKind = "principle"` (the historical use): an embedding /
//    semantic drift event for a Principle. `targetId` references the
//    principle id; the method-* fields are empty.
//
// 2. `targetKind = "method"` (added with the Method Drift work):
//    nightly per-method calibration drift. `methodName`, `methodVersion`,
//    `methodDomain`, `windowDays` are required and `targetId` is set to
//    `method:<name>@<version>` so existing consumers see *some* id even
//    if they do not understand the new kind.
//
// The deterministic id for method drift events is a UUID-v5 of the
// (organization, method, version, domain, window, window_end) tuple,
// so re-running the nightly evaluator is idempotent.

model DriftEvent {
  id             String @id @default(cuid())
  organizationId String

  noosphereId                 String?  @unique
  targetId                    String
  targetKind                  String   @default("principle")
  episodeId                   String   @default("")
  observedAt                  DateTime
  driftScore                  Float    @default(0)
  notes                       String   @default("")
  claimSequenceIdsJson        String   @default("[]")
  naturalLanguageSummary      String   @default("")
  earliestInconsistentClaimId String   @default("")
  authorTopicKey              String   @default("")
  topicId                     String   @default("")

  // ── Method drift fields (null/empty for principle drift) ────────────
  methodName       String?
  methodVersion    String?
  methodDomain     String?
  windowDays       Int?
  severity         String? // "ok" | "warn" | "escalate" | "insufficient"
  sigma            Float?
  pValue           Float?
  seed             Int?
  sampleSize       Int?
  calibrationSlope Float?
  baselineSlope    Float?
  brierMean        Float?
  baselineBrier    Float?
  directionalBias  Float?
  evidence         Json?

  organization Organization @relation(fields: [organizationId], references: [id], onDelete: Restrict)

  @@index([organizationId])
  @@index([organizationId, methodName, methodVersion, methodDomain, observedAt])
  @@index([targetKind, observedAt])
}

// ── ResearchSuggestion — mirrors noosphere.models.ResearchSuggestion ───────

model ResearchSuggestion {
